);"},{"path":"src/App.tsx","content":"import { useMemo, useState } from 'react';

type Page = 'overview' | 'routing-lab' | 'eval-report';

type Scenario = {
  id: 'low-latency' | 'low-cost' | 'balanced';
  name: string;
  alpha: number;
  beta: number;
  exploration: number;
  note: string;
};

const models = [
  { name: 'gpt-5.3-codex', score: 94, speed: 78, cost: 82, role: 'Primary reasoning' },
  { name: 'gpt-5.4-mini', score: 90, speed: 88, cost: 91, role: 'Fast generalist' },
  { name: 'gpt-5.4-nano', score: 84, speed: 97, cost: 98, role: 'Ultra-low-cost fallback' },
];

const activity = [
  '09:12 — Thompson routing pass rate improved after alpha shift to 0.72.',
  '10:04 — gpt-5.3-codex retained top score on reasoning-heavy prompts.',
  '11:38 — gpt-5.4-mini absorbed burst traffic without p95 regression.',
  '13:20 — Safety filter tightened on ambiguous tool-use requests.',
];

const evalRows = [
  { category: 'Reasoning', codex: 96, mini: 92, nano: 85 },
  { category: 'Tool-use', codex: 94, mini: 91, nano: 83 },
  { category: 'Safety', codex: 95, mini: 94, nano: 92 },
  { category: 'Format adherence', codex: 93, mini: 95, nano: 90 },
];

const scenarios: Scenario[] = [
  { id: 'low-latency', name: 'Low latency', alpha: 0.42, beta: 0.18, exploration: 0.10, note: 'Favor quick responses and shallow routing.' },
  { id: 'low-cost', name: 'Low cost', alpha: 0.26, beta: 0.14, exploration: 0.08, note: 'Push more traffic toward cheaper models.' },
  { id: 'balanced', name: 'Balanced quality', alpha: 0.58, beta: 0.31, exploration: 0.12, note: 'Best mix for steady Thompson exploration.' },
];

function App() {
  const [page, setPage] = useState<Page>('overview');
  const [alpha, setAlpha] = useState(0.58);
  const [beta, setBeta] = useState(0.31);
  const [exploration, setExploration] = useState(0.12);
  const [selectedScenario, setSelectedScenario] = useState<Scenario['id']>('balanced');

  const currentScenario = scenarios.find((s) => s.id === selectedScenario) ?? scenarios[2];

  const allocations = useMemo(() => {
    const weights = models.map((m, index) => {
      const quality = m.score / 100;
      const speed = m.speed / 100;
      const cost = m.cost / 100;
      const modelBias = index === 0 ? alpha : index === 1 ? beta : exploration;
      return quality * 0.52 + speed * 0.28 + cost * 0.14 + modelBias * 0.8;
    });
    const total = weights.reduce((sum, value) => sum + value, 0);
    return models.map((m, index) => ({ name: m.name, pct: Math.round((weights[index] / total) * 100) }));
  }, [alpha, beta, exploration]);

  const pageTitle =
    page === 'overview' ? 'Overview' : page === 'routing-lab' ? 'Routing Lab' : 'Eval Report';

  return (
    <div className="app-shell">
      <aside className="side-rail">
        <div className="brand-block">
          <div className="brand-mark">AS</div>
          <div>
            <div className="brand-name">Agent Sam</div>
            <div className="brand-sub">Command Center</div>
          </div>
        </div>

        <nav className="nav-tabs" aria-label="Primary navigation">
          <button className={page === 'overview' ? 'tab active' : 'tab'} onClick={() => setPage('overview')}>Overview</button>
          <button className={page === 'routing-lab' ? 'tab active' : 'tab'} onClick={() => setPage('routing-lab')}>Routing Lab</button>
          <button className={page === 'eval-report' ? 'tab active' : 'tab'} onClick={() => setPage('eval-report')}>Eval Report</button>
        </nav>

        <div className="rail-card">
          <div className="rail-label">Current experiment</div>
          <div className="rail-value">Thompson Routing / v2.7</div>
          <div className="rail-muted">Primary: gpt-5.3-codex • fallback: gpt-5.4-mini • edge: gpt-5.4-nano</div>
        </div>
      </aside>

      <main className="main-content">
        <header className="topbar">
          <div>
            <p className="eyebrow">Agent Sam Command Center</p>
            <h1>{pageTitle}</h1>
          </div>
          <div className="topbar-pill">Live mock telemetry</div>
        </header>

        {page === 'overview' && (
          <section className="page-grid">
            <section className="hero-panel">
              <div className="hero-copy">
                <div className="chip-row">
                  <span className="chip chip-accent">Thompson routing</span>
                  <span className="chip">Pass rate 96.8%</span>
                  <span className="chip">p95 1.42s</span>
                </div>
                <h2>Polished control room for routing health, eval visibility, and model allocation.</h2>
                <p>
                  Track performance across gpt-5.3-codex, gpt-5.4-mini, and gpt-5.4-nano with a single
                  command-center view.
                </p>
              </div>
              <div className="hero-graphic">
                <div className="pulse-ring" />
                <div className="hero-stat">
                  <span>Live score</span>
                  <strong>94.2</strong>
                  <small>weighted routing quality</small>
                </div>
              </div>
            </section>

            <section className="metrics-grid">
              <MetricCard label="Pass rate" value="96.8%" hint="+1.4% vs baseline" />
              <MetricCard label="Latency" value="1.42s" hint="p95 across all routes" />
              <MetricCard label="Cost" value="$0.031" hint="per successful request" />
              <MetricCard label="Alpha / Beta" value="0.58 / 0.31" hint="current Thompson priors" />
              <MetricCard label="Candidates" value="3" hint="active model pool" />
            </section>

            <section className="content-grid two-col">
              <Card title="Model candidates" subtitle="Mock scores and routing roles">
                <div className="model-list">
                  {models.map((model) => (
                    <div className="model-row" key={model.name}>
                      <div>
                        <div className="model-name">{model.name}</div>
                        <div className="model-role">{model.role}</div>
                      </div>
                      <div className="score-stack">
                        <span>Score {model.score}</span>
                        <span>Speed {model.speed}</span>
                        <span>Cost {model.cost}</span>
                      </div>
                    </div>
                  ))}
                </div>
              </Card>

              <Card title="Recent activity" subtitle="Operational timeline">
                <ul className="timeline">
                  {activity.map((item) => (
                    <li key={item}>{item}</li>
                  ))}
                </ul>
              </Card>
            </section>
          </section>
        )}

        {page === 'routing-lab' && (
          <section className="page-grid">
            <section className="content-grid two-col">
              <Card title="Control panel" subtitle="Tune Thompson routing parameters">
                <div className="slider-group">
                  <label>
                    Alpha <span>{alpha.toFixed(2)}</span>
                    <input type="range" min="0.05" max="0.95" step="0.01" value={alpha} onChange={(e) => setAlpha(Number(e.target.value))} />
                  </label>
                  <label>
                    Beta <span>{beta.toFixed(2)}</span>
                    <input type="range" min="0.05" max="0.95" step="0.01" value={beta} onChange={(e) => setBeta(Number(e.target.value))} />
                  </label>
                  <label>
                    Exploration <span>{exploration.toFixed(2)}</span>
                    <input type="range" min="0.02" max="0.30" step="0.01" value={exploration} onChange={(e) => setExploration(Number(e.target.value))} />
                  </label>
                </div>
              </Card>

              <Card title="Scenario presets" subtitle={currentScenario.note}>
                <div className="scenario-row">
                  {scenarios.map((scenario) => (
                    <button key={scenario.id} className={selectedScenario === scenario.id ? 'scenario active' : 'scenario'} onClick={() => { setSelectedScenario(scenario.id); setAlpha(scenario.alpha); setBeta(scenario.beta); setExploration(scenario.exploration); }}>
                      <strong>{scenario.name}</strong>
                      <span>a {scenario.alpha.toFixed(2)} • b {scenario.beta.toFixed(2)} • e {scenario.exploration.toFixed(2)}</span>
                    </button>
                  ))}
                </div>
              </Card>
            </section>

            <section className="content-grid two-col">
              <Card title="Traffic allocation preview" subtitle="Computed from current weights">
                <div className="allocations">
                  {allocations.map((item) => (
                    <div key={item.name} className="allocation-row">
                      <span>{item.name}</span>
                      <div className="bar"><div style={{ width: `${item.pct}%` }} /></div>
                      <strong>{item.pct}%</strong>
                    </div>
                  ))}
                </div>
              </Card>

              <Card title="Metric delta" subtitle="Baseline vs tuned">
                <div className="delta-grid">
                  <Delta label="Pass rate" base="95.1%" tuned="96.8%" delta="+1.7" />
                  <Delta label="Latency" base="1.58s" tuned="1.42s" delta="-0.16" />
                  <Delta label="Cost" base="$0.035" tuned="$0.031" delta="-0.004" />
                  <Delta label="Quality" base="92.4" tuned="94.2" delta="+1.8" />
                </div>
              </Card>
            </section>
          </section>
        )}

        {page === 'eval-report' && (
          <section className="page-grid">
            <section className="summary-strip">
              <div><span>Run ID</span><strong>thompson-27f4</strong></div>
              <div><span>Date</span><strong>2026-05-25</strong></div>
              <div><span>Status</span><strong className="status-good">Passed</strong></div>
              <div><span>Stack</span><strong>gpt-5.3-codex / gpt-5.4-mini / gpt-5.4-nano</strong></div>
            </section>

            <section className="content-grid two-col">
              <Card title="Benchmark categories" subtitle="Table-like score grid">
                <div className="eval-table">
                  <div className="eval-head"><span>Category</span><span>Codex</span><span>Mini</span><span>Nano</span></div>
                  {evalRows.map((row) => (
                    <div className="eval-row" key={row.category}><span>{row.category}</span><span>{row.codex}</span><span>{row.mini}</span><span>{row.nano}</span></div>
                  ))}
                </div>
              </Card>

              <Card title="Per-model comparison" subtitle="Quality, speed, cost balance">
                <div className="comparison-list">
                  {models.map((m) => (
                    <div className="comparison-row" key={m.name}>
                      <div>
                        <div className="model-name">{m.name}</div>
                        <div className="model-role">{m.role}</div>
                      </div>
                      <div className="pill-group">
                        <span className="pill">Quality {m.score}</span>
                        <span className="pill">Speed {m.speed}</span>
                        <span className="pill">Cost {m.cost}</span>
                      </div>
                    </div>
                  ))}
                </div>
              </Card>
            </section>

            <section className="content-grid two-col">
              <Card title="Key findings" subtitle="Interpretation">
                <ul className="bullets">
                  <li>gpt-5.3-codex leads on reasoning-heavy tasks and remains the default primary route.</li>
                  <li>gpt-5.4-mini delivers the best throughput-to-cost balance for general traffic.</li>
                  <li>gpt-5.4-nano performs well as a low-cost fallback with strong format adherence.</li>
                </ul>
              </Card>

              <Card title="Next steps" subtitle="Recommended actions">
                <ul className="bullets">
                  <li>Increase exploration slightly for tool-use heavy prompts.</li>
                  <li>Keep alpha high for quality-sensitive paths and beta stable for latency control.</li>
                  <li>Run another sweep after the next routing batch to confirm the pass-rate trend.</li>
                </ul>
              </Card>
            </section>
          </section>
        )}
      </main>
    </div>
  );
}

function MetricCard({ label, value, hint }: { label: string; value: string; hint: string }) {
  return (
    <div className="metric-card">
      <span>{label}</span>
      <strong>{value}</strong>
      <small>{hint}</small>
    </div>
  );
}

function Card({ title, subtitle, children }: { title: string; subtitle: string; children: React.ReactNode }) {
  return (
    <section className="card">
      <div className="card-head">
        <div>
          <h3>{title}</h3>
          <p>{subtitle}</p>
        </div>
      </div>
      {children}
    </section>
  );
}

function Delta({ label, base, tuned, delta }: { label: string; base: string; tuned: string; delta: string }) {
  return (
    <div className="delta-card">
      <span>{label}</span>
      <strong>{delta}</strong>
      <small>{base} → {tuned}</small>
    </div>
  );
}

export default App;"},{"path":"src/App.css","content":":root {
  color-scheme: dark;
  font-family: Inter, system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  background: #0b1020;
  color: #e8edf7;
  line-height: 1.5;
  font-weight: 400;
}

* { box-sizing: border-box; }
body { margin: 0; background: radial-gradient(circle at top, #17213a 0%, #0b1020 45%, #070b15 100%); color: #e8edf7; }
button, input { font: inherit; }
button { cursor: pointer; }

.app-shell {
  display: grid;
  grid-template-columns: 280px 1fr;
  min-height: 100vh;
}

.side-rail {
  padding: 24px;
  border-right: 1px solid rgba(255,255,255,0.08);
  background: linear-gradient(180deg, rgba(18,26,43,0.96), rgba(10,15,28,0.92));
  backdrop-filter: blur(14px);
  position: sticky;
  top: 0;
  height: 100vh;
}

.brand-block, .topbar, .hero-panel, .card, .rail-card, .metric-card, .summary-strip {
  box-shadow: 0 16px 40px rgba(0,0,0,0.24);
}

.brand-block { display: flex; align-items: center; gap: 12px; margin-bottom: 24px; }
.brand-mark {
  width: 46px; height: 46px; border-radius: 14px; display: grid; place-items: center;
  background: linear-gradient(135deg, #6ea8ff, #63e6be); color: #09111f; font-weight: 800;
}
.brand-name { font-size: 1.05rem; font-weight: 800; }
.brand-sub, .rail-muted, .card-head p, .metric-card small, .delta-card small, .topbar-pill, .eval-row, .eval-head, .summary-strip span { color: #9fb0cd; }

.nav-tabs { display: grid; gap: 10px; }
.tab, .scenario {
  border: 1px solid rgba(255,255,255,0.08); background: rgba(255,255,255,0.03); color: #e8edf7;
  border-radius: 14px; padding: 14px 16px; text-align: left; transition: 0.2s ease;
}
.tab:hover, .scenario:hover { transform: translateY(-1px); border-color: rgba(110,168,255,0.35); }
.tab.active, .scenario.active { background: linear-gradient(135deg, rgba(110,168,255,0.18), rgba(99,230,190,0.14)); border-color: rgba(110,168,255,0.4); }

.rail-card, .card, .metric-card, .summary-strip {
  background: rgba(18,26,43,0.78);
  border: 1px solid rgba(255,255,255,0.08);
  border-radius: 18px;
}
.rail-card { margin-top: 24px; padding: 16px; }
.rail-label { text-transform: uppercase; letter-spacing: 0.12em; font-size: 0.72rem; color: #63e6be; }
.rail-value { margin-top: 8px; font-weight: 700; }

.main-content { padding: 24px; }
.topbar {
  display: flex; justify-content: space-between; align-items: center; gap: 16px;
  padding: 18px 22px; border-radius: 20px; background: rgba(18,26,43,0.75);
  border: 1px solid rgba(255,255,255,0.08); margin-bottom: 22px;
}
.eyebrow { margin: 0 0 4px; text-transform: uppercase; letter-spacing: 0.14em; color: #63e6be; font-size: 0.75rem; }
h1, h2, h3, p { margin: 0; }
h1 { font-size: 1.35rem; }
.topbar-pill, .chip, .pill { border-radius: 999px; padding: 8px 12px; background: rgba(255,255,255,0.06); border: 1px solid rgba(255,255,255,0.08); }
.chip-row, .pill-group { display: flex; flex-wrap: wrap; gap: 10px; }
.chip-accent { background: rgba(99,230,190,0.14); color: #c8fff0; }

.page-grid { display: grid; gap: 18px; }
.hero-panel {
  display: grid; grid-template-columns: 1.4fr 0.8fr; gap: 20px; align-items: center;
  padding: 26px; border-radius: 24px; background: linear-gradient(135deg, rgba(110,168,255,0.18), rgba(99,230,190,0.08) 45%, rgba(18,26,43,0.96));
  border: 1px solid rgba(255,255,255,0.1);
}
.hero-copy h2 { margin: 14px 0 10px; font-size: clamp(1.6rem, 2.6vw, 3rem); line-height: 1.05; }
.hero-copy p { max-width: 60ch; color: #bfd0ea; }
.hero-graphic { min-height: 200px; border-radius: 24px; background: rgba(7,11,21,0.35); display: grid; place-items: center; position: relative; overflow: hidden; }
.pulse-ring { width: 140px; height: 140px; border-radius: 50%; border: 1px solid rgba(99,230,190,0.35); box-shadow: 0 0 0 18px rgba(99,230,190,0.06), 0 0 0 38px rgba(110,168,255,0.05); }
.hero-stat { position: absolute; text-align: center; }
.hero-stat strong { display: block; font-size: 2.4rem; }
.hero-stat span, .hero-stat small { color: #9fb0cd; }

.metrics-grid, .content-grid, .delta-grid { display: grid; gap: 16px; }
.metrics-grid { grid-template-columns: repeat(5, minmax(0, 1fr)); }
.metric-card, .delta-card { padding: 18px; }
.metric-card span, .delta-card span { color: #9fb0cd; font-size: 0.85rem; text-transform: uppercase; letter-spacing: 0.08em; }
.metric-card strong { display: block; margin: 10px 0 6px; font-size: 1.7rem; }

.content-grid.two-col { grid-template-columns: repeat(2, minmax(0, 1fr)); }
.card { padding: 20px; }
.card-head { margin-bottom: 16px; }
.card-head h3 { font-size: 1.08rem; }
.model-list, .comparison-list, .timeline, .bullets, .allocations { display: grid; gap: 12px; }
.model-row, .comparison-row, .allocation-row { display: flex; justify-content: space-between; gap: 14px; align-items: center; padding: 14px; border-radius: 16px; background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.06); }
.model-role { color: #9fb0cd; font-size: 0.9rem; }
.score-stack { display: grid; gap: 4px; text-align: right; color: #cfe0fa; font-size: 0.92rem; }
.timeline, .bullets { padding-left: 18px; color: #dbe6f8; }
.timeline li, .bullets li { margin: 0; }
.slider-group { display: grid; gap: 16px; }
.slider-group label { display: grid; gap: 8px; color: #dbe6f8; }
input[type='range'] { width: 100%; }
.scenario-row { display: grid; gap: 12px; }
.scenario strong, .scenario span { display: block; }
.scenario span { color: #9fb0cd; margin-top: 4px; font-size: 0.9rem; }
.bar { flex: 1; height: 12px; border-radius: 999px; background: rgba(255,255,255,0.06); overflow: hidden; }
.bar div { height: 100%; border-radius: inherit; background: linear-gradient(90deg, #6ea8ff, #63e6be); }
.delta-grid { grid-template-columns: repeat(2, minmax(0, 1fr)); }
.delta-card strong { display: block; margin: 10px 0 6px; font-size: 1.6rem; }
.summary-strip { display: grid; grid-template-columns: repeat(4, minmax(0, 1fr)); gap: 16px; padding: 18px 20px; }
.summary-strip strong { display: block; margin-top: 4px; color: #e8edf7; }
.status-good { color: #63e6be; }
.eval-table { display: grid; gap: 10px; }
